import React from 'react';
import { useNavigate } from 'react-router-dom';
import NeuralBackground from '../components/NeuralBackground';

const ROLES = [
  {
    id: 'researcher',
    icon: '🔬',
    title: 'Researcher',
    tagline: 'For neuroscience & clinical researchers',
    features: [
      'Cohort management & batch analysis',
      'Group statistics and comparisons',
      'CSV / JSON export',
      'Region-of-interest selection',
      'MPI-LEMON dataset guidance',
    ],
  },
  {
    id: 'individual',
    icon: '🧘',
    title: 'Individual',
    tagline: 'For personal wellbeing insights',
    features: [
      'Plain-English results summary',
      'Wellbeing trend over time',
      'Multi-modal score cards',
      'Personalised recommendations',
      'Privacy-first framing',
    ],
  },
];

const PREVIEW_CARDS = [
  { label: 'Brain activation', text: 'Grad-CAM heatmaps highlight which regions drove the prediction — amygdala, anterior cingulate, and more.' },
  { label: 'Multi-modal correlation', text: 'Cross-reference fMRI signals with blood pressure, HRV, PHQ-9, and GAD-7 for a richer picture.' },
  { label: 'Wellbeing tracking', text: 'Track neuroticism, trait anxiety, and chronic stress z-scores across multiple sessions.' },
];

export default function LandingPage({ userRole, setRole }) {
  const navigate  = useNavigate();
  const [selected, setSelected] = React.useState(userRole || null);

  function handleStart() {
    if (!selected) return;
    setRole(selected);
    navigate('/upload');
  }

  return (
    <div style={{ minHeight: 'calc(100vh - 52px)', display: 'flex', flexDirection: 'column', background: '#0D1117' }}>

      {/* ── Hero ─────────────────────────────────────────────────────────── */}
      <div style={{ position: 'relative', overflow: 'hidden', padding: '56px 24px 48px', textAlign: 'center' }}>
        <NeuralBackground />
        <div style={{ position: 'relative', zIndex: 1, maxWidth: 640, margin: '0 auto' }}>
          <div style={{ fontFamily: "'DM Mono', monospace", fontSize: 11, color: '#7EE7D0', letterSpacing: '.12em', textTransform: 'uppercase', marginBottom: 14 }}>
            NeuroCNN v1 · MPI-LEMON · Multi-modal wellbeing
          </div>
          <h1 style={{ fontFamily: "'DM Mono', monospace", fontSize: 34, fontWeight: 500, color: '#F0F6FC', lineHeight: 1.2, marginBottom: 14 }}>
            Wellbeing Insight
          </h1>
          <p style={{ color: '#8B949E', fontSize: 15, lineHeight: 1.7, maxWidth: 500, margin: '0 auto 28px' }}>
            Analyse resting-state fMRI scans alongside physiological markers and validated questionnaires to surface meaningful mental wellbeing insights.
          </p>
        </div>
      </div>

      {/* ── Role selection ────────────────────────────────────────────────── */}
      <div style={{ maxWidth: 780, margin: '0 auto', width: '100%', padding: '0 24px' }}>
        <div style={{ fontFamily: "'DM Mono', monospace", fontSize: 11, color: '#8B949E', letterSpacing: '.1em', textTransform: 'uppercase', marginBottom: 16, textAlign: 'center' }}>
          Who are you?
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 24 }}>
          {ROLES.map(role => (
            <div
              key={role.id}
              className={`role-card${selected === role.id ? ' selected' : ''}`}
              onClick={() => setSelected(role.id)}
            >
              <div style={{ fontSize: 28, marginBottom: 10 }}>{role.icon}</div>
              <div style={{ fontFamily: "'DM Mono', monospace", fontSize: 16, fontWeight: 500, color: '#F0F6FC', marginBottom: 4 }}>
                {role.title}
              </div>
              <div style={{ fontSize: 12, color: '#7EE7D0', marginBottom: 14 }}>{role.tagline}</div>
              <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'flex', flexDirection: 'column', gap: 6 }}>
                {role.features.map(f => (
                  <li key={f} style={{ fontSize: 13, color: '#8B949E', display: 'flex', gap: 8 }}>
                    <span style={{ color: '#7EE7D0', flexShrink: 0 }}>✓</span>
                    {f}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>

        <div style={{ textAlign: 'center', marginBottom: 48 }}>
          <button
            onClick={handleStart}
            disabled={!selected}
            className="btn btn-primary btn-lg"
            style={{ opacity: selected ? 1 : 0.45, cursor: selected ? 'pointer' : 'not-allowed' }}
          >
            Get started →
          </button>
          <div style={{ fontSize: 12, color: '#57606A', marginTop: 10 }}>
            You can switch roles at any time from the navigation bar.
          </div>
        </div>
      </div>

      {/* ── Preview strip ─────────────────────────────────────────────────── */}
      <div style={{ background: '#161B22', borderTop: '1px solid #30363D', padding: '32px 24px' }}>
        <div style={{ maxWidth: 900, margin: '0 auto' }}>
          <div style={{ fontFamily: "'DM Mono', monospace", fontSize: 11, color: '#8B949E', textTransform: 'uppercase', letterSpacing: '.1em', textAlign: 'center', marginBottom: 20 }}>
            What you get
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16 }}>
            {PREVIEW_CARDS.map(c => (
              <div key={c.label} style={{ background: '#1C2333', borderRadius: 10, padding: '18px 20px', border: '1px solid #30363D' }}>
                <div style={{ fontFamily: "'DM Mono', monospace", fontSize: 12, color: '#7EE7D0', marginBottom: 8 }}>{c.label}</div>
                <div style={{ fontSize: 13, color: '#8B949E', lineHeight: 1.6 }}>{c.text}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
